package com.example.inventory.controller;
import com.example.inventory.model.*; import com.example.inventory.service.InventoryService; import org.springframework.stereotype.Controller; import org.springframework.ui.Model; import org.springframework.web.bind.annotation.*;
@Controller
public class InventoryController { private final InventoryService service; public InventoryController(InventoryService service){this.service=service;} @GetMapping("/") public String index(){return "index";} @GetMapping("/shops") public String shops(Model m){m.addAttribute("shops",service.shops());return "shops";} @GetMapping("/shops/new") public String newShop(Model m){m.addAttribute("shop",new Shop());return "shop-form";} @GetMapping("/shops/{code}/edit") public String editShop(@PathVariable String code, Model m){m.addAttribute("shop",service.shop(code));return "shop-form";} @PostMapping("/shops/save") public String saveShop(Shop shop){service.saveShop(shop);return "redirect:/shops";} @PostMapping("/shops/{code}/delete") public String deleteShop(@PathVariable String code, Model m){try{service.deleteShop(code);return "redirect:/shops";}catch(IllegalArgumentException e){m.addAttribute("error",e.getMessage());m.addAttribute("shops",service.shops());return "shops";}} @GetMapping("/buyins") public String buyIns(Model m){m.addAttribute("list",service.buyIns());return "buyins";} @GetMapping("/buyins/new") public String newBuyIn(Model m){m.addAttribute("code",service.nextBuyInCode());m.addAttribute("shops",service.shops());return "buyin-form";} @PostMapping("/buyins/save") public String saveBuyIn(BuyIn b, Model m){try{service.addBuyIn(b);return "redirect:/buyins";}catch(IllegalArgumentException e){m.addAttribute("error",e.getMessage());m.addAttribute("code",service.nextBuyInCode());m.addAttribute("shops",service.shops());return "buyin-form";}} @GetMapping("/sellouts") public String sellOuts(Model m){m.addAttribute("list",service.sellOuts());return "sellouts";} @GetMapping("/sellouts/new") public String newSellOut(Model m){m.addAttribute("code",service.nextSellOutCode());m.addAttribute("shops",service.shops());return "sellout-form";} @PostMapping("/sellouts/save") public String saveSellOut(SellOut s, Model m){try{service.addSellOut(s);return "redirect:/sellouts";}catch(IllegalArgumentException e){m.addAttribute("error",e.getMessage());m.addAttribute("code",service.nextSellOutCode());m.addAttribute("shops",service.shops());return "sellout-form";}} @GetMapping("/storages") public String storages(Model m){m.addAttribute("list",service.storages());return "storages";} }
